proof_block:
// The ensures of det_pop_unique is shaped (A_conjunction) ==> det_pop_unique_equal(...).
// At the top of the body the antecedent A is NOT yet in the proof context (it is
// the antecedent of the implication, not a hypothesis), which is why the previous
// attempt's unconditional asserts like `assert(r1 == pre_self_@[pre_self_.len() - 1])`
// failed — z3 has no fact pinning r1 at that point.
//
// We bring A into scope with an explicit `if (A) { ... }`, derive the per-component
// equalities inside the branch, and let z3 discharge `A ==> det_pop_unique_equal`
// by combining the in-branch facts with the trivial false-antecedent case.
if ({
    &&& post1_self_.wf()
    &&& post1_self_@.len() == pre_self_@.len() - 1
    &&& r1 == pre_self_@[pre_self_.len() - 1]
    &&& post1_self_@ =~= pre_self_@.drop_last()
    &&& post1_self_@.no_duplicates()
    &&& post2_self_.wf()
    &&& post2_self_@.len() == pre_self_@.len() - 1
    &&& r2 == pre_self_@[pre_self_.len() - 1]
    &&& post2_self_@ =~= pre_self_@.drop_last()
    &&& post2_self_@.no_duplicates()
}) {
    // Inside this branch every conjunct of A is a known fact, so all the
    // assertions below are sound.

    // r1 and r2 are each fixed to the *same* element of pre_self_@.
    assert(r1 == pre_self_@[pre_self_.len() - 1]);
    assert(r2 == pre_self_@[pre_self_.len() - 1]);
    assert(r1 == r2);

    // Each post-view is sequence-extensionally equal to pre_self_@.drop_last().
    assert(post1_self_@ =~= pre_self_@.drop_last());
    assert(post2_self_@ =~= pre_self_@.drop_last());

    // Transitivity through pre_self_@.drop_last() gives view-equality directly,
    // and re-asserting with =~= re-triggers Seq::ext_equal so z3 closes it.
    assert(post1_self_@ =~= post2_self_@);
    assert(post1_self_@ == post2_self_@);

    // Lengths are both pre_self_@.len() - 1, hence equal.
    assert(post1_self_.len == post2_self_.len);
    assert(post1_self_@.len() == post2_self_@.len());

    // Pointwise equality of the post views (this gives z3 the per-index
    // facts it needs to derive .data@ equality on the live prefix).
    assert forall|i: int| 0 <= i < post1_self_@.len() implies
        post1_self_@[i] == post2_self_@[i] by {
        assert(post1_self_@[i] == pre_self_@.drop_last()[i]);
        assert(post2_self_@[i] == pre_self_@.drop_last()[i]);
    }
}
